class Solution:
    def minOperations(self, nums, numsDivide):
        from math import gcd
        g = 0
        for x in numsDivide:
            g = gcd(g, x)
        for cnt, v in enumerate(sorted(nums)):
            if g % v == 0:
                return cnt
        return -1

