class Solution:
    def minOperations(self, nums, numsDivide):
        from math import gcd
        from functools import reduce
        g = reduce(gcd, numsDivide)
        nums = sorted(nums)
        for i, v in enumerate(nums):
            if g % v == 0:
                return i
        return -1

