var minOperations = function(nums, numsDivide) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    let g = 0;
    for (const x of numsDivide) g = gcd(g, x);
    nums.sort((a, b) => a - b);
    for (let i = 0; i < nums.length; i++) {
        if (g % nums[i] === 0) return i;
    }
    return -1;
};
